// ── autocomplete-search ───────────────────────────
const EvalAutocompleteSearchfruits = [
  { id: 'apple', label: 'Apple' },
  { id: 'apricot', label: 'Apricot' },
  { id: 'banana', label: 'Banana' },
  { id: 'blueberry', label: 'Blueberry' },
  { id: 'cherry', label: 'Cherry' },
  { id: 'coconut', label: 'Coconut' },
  { id: 'cranberry', label: 'Cranberry' },
  { id: 'dragonfruit', label: 'Dragon Fruit' },
  { id: 'fig', label: 'Fig' },
  { id: 'grape', label: 'Grape' },
  { id: 'grapefruit', label: 'Grapefruit' },
  { id: 'guava', label: 'Guava' },
  { id: 'kiwi', label: 'Kiwi' },
  { id: 'lemon', label: 'Lemon' },
  { id: 'lime', label: 'Lime' },
  { id: 'mango', label: 'Mango' },
  { id: 'melon', label: 'Melon' },
  { id: 'orange', label: 'Orange' },
  { id: 'papaya', label: 'Papaya' },
  { id: 'peach', label: 'Peach' },
  { id: 'pear', label: 'Pear' },
  { id: 'pineapple', label: 'Pineapple' },
  { id: 'plum', label: 'Plum' },
  { id: 'pomegranate', label: 'Pomegranate' },
  { id: 'raspberry', label: 'Raspberry' },
  { id: 'strawberry', label: 'Strawberry' },
  { id: 'tangerine', label: 'Tangerine' },
  { id: 'watermelon', label: 'Watermelon' },
];

function EvalAutocompleteSearch() {
  const [query, setQuery] = useState('');
  const [selected, setSelected] = useState('');

  const filtered = EvalAutocompleteSearchfruits.filter((fruit) =>
    fruit.label.toLowerCase().includes(query.toLowerCase()),
  );

  return (
    <Combobox.Root
      inputValue={query}
      onInputChange={setQuery}
      selectedKey={selected}
      onSelectionChange={(key) => setSelected(String(key))}
      menuTrigger="focus"
    >
      <Combobox.Label>Search EvalAutocompleteSearchfruits</Combobox.Label>
      <Combobox.InputGroup>
        <Combobox.Input placeholder="Type to search..." />
        <Combobox.Trigger />
      </Combobox.InputGroup>
      <Combobox.Popover>
        <Combobox.ListBox>
          {filtered.length > 0 ? (
            filtered.map((fruit) => (
              <Combobox.Item
                key={fruit.id}
                id={fruit.id}
                textValue={fruit.label}
              >
                {fruit.label}
              </Combobox.Item>
            ))
          ) : (
            <Combobox.Empty>No EvalAutocompleteSearchfruits found</Combobox.Empty>
          )}
        </Combobox.ListBox>
      </Combobox.Popover>
    </Combobox.Root>
  );
}

